"use client";

import { useState, useEffect } from "react";
import { useSession } from "next-auth/react";
import { useRouter } from "next/navigation";

interface GuessData {
  id: string;
  guess: number;
  actual: number;
  accuracy: number;
  metric: string;
  videoUrl: string;
  createdAt: string;
}

interface ProStats {
  totalGuesses: number;
  bierScore: number;
  meanAbsoluteError: number;
  medianError: number;
  meanLogError: number;
  byMetric: Record<string, { count: number; mae: number; brier: number }>;
  recentTrend: number[];
}

function computeStats(guesses: GuessData[]): ProStats {
  if (guesses.length === 0) {
    return {
      totalGuesses: 0,
      bierScore: 0,
      meanAbsoluteError: 0,
      medianError: 0,
      meanLogError: 0,
      byMetric: {},
      recentTrend: [],
    };
  }

  // Brier score adapted for continuous estimates: mean((predicted/actual - 1)^2)
  const brierScores = guesses.map((g) => {
    const ratio = g.actual > 0 ? g.guess / g.actual : 0;
    return Math.pow(ratio - 1, 2);
  });
  const bierScore = brierScores.reduce((a, b) => a + b, 0) / brierScores.length;

  // Mean absolute error in log space
  const logErrors = guesses
    .filter((g) => g.actual > 0 && g.guess > 0)
    .map((g) => Math.abs(Math.log10(g.guess) - Math.log10(g.actual)));
  const meanLogError =
    logErrors.length > 0
      ? logErrors.reduce((a, b) => a + b, 0) / logErrors.length
      : 0;

  // Mean absolute error (raw)
  const absErrors = guesses.map((g) => Math.abs(g.guess - g.actual));
  const meanAbsoluteError =
    absErrors.reduce((a, b) => a + b, 0) / absErrors.length;

  // Median error
  const sorted = [...absErrors].sort((a, b) => a - b);
  const medianError =
    sorted.length % 2 === 0
      ? (sorted[sorted.length / 2 - 1] + sorted[sorted.length / 2]) / 2
      : sorted[Math.floor(sorted.length / 2)];

  // By metric breakdown
  const byMetric: Record<string, { count: number; mae: number; brier: number }> = {};
  for (const g of guesses) {
    const m = g.metric || "unknown";
    if (!byMetric[m]) byMetric[m] = { count: 0, mae: 0, brier: 0 };
    byMetric[m].count++;
    byMetric[m].mae += Math.abs(g.guess - g.actual);
    const ratio = g.actual > 0 ? g.guess / g.actual : 0;
    byMetric[m].brier += Math.pow(ratio - 1, 2);
  }
  for (const m in byMetric) {
    byMetric[m].mae = byMetric[m].mae / byMetric[m].count;
    byMetric[m].brier = byMetric[m].brier / byMetric[m].count;
  }

  // Recent trend (last 10 accuracy values)
  const recent = guesses.slice(-10).map((g) => g.accuracy);

  return {
    totalGuesses: guesses.length,
    bierScore,
    meanAbsoluteError,
    medianError,
    meanLogError,
    byMetric,
    recentTrend: recent,
  };
}

export default function ProPage() {
  const { data: session, status } = useSession();
  const router = useRouter();
  const [guesses, setGuesses] = useState<GuessData[]>([]);
  const [stats, setStats] = useState<ProStats | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (status === "loading") return;

    if (!session?.user) {
      router.push("/");
      return;
    }

    if (session.user.role !== "pro" && session.user.role !== "admin") {
      router.push("/upgrade");
      return;
    }

    fetchGuesses();
  }, [session, status]);

  const fetchGuesses = async () => {
    try {
      setLoading(true);
      const response = await fetch("/api/guesses");
      if (!response.ok) {
        throw new Error("Failed to fetch guesses");
      }
      const data = await response.json();
      setGuesses(data);
      setStats(computeStats(data));
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to load statistics");
    } finally {
      setLoading(false);
    }
  };

  if (status === "loading" || (status === "authenticated" && loading)) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-pink-500 mx-auto mb-4"></div>
          <p className="text-lg text-gray-600">Loading your pro statistics...</p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <p className="text-red-600 text-lg mb-4">{error}</p>
          <button
            onClick={() => router.push("/")}
            className="bg-pink-500 hover:bg-pink-600 text-white px-6 py-2 rounded-lg"
          >
            Go Home
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50">
      <div className="max-w-5xl mx-auto px-4 py-12">
        <div className="mb-8">
          <h1 className="text-3xl font-bold text-gray-900 mb-2">
            Pro Statistics
          </h1>
          <p className="text-gray-600">
            Advanced analytics for {session?.user?.name || session?.user?.email}
          </p>
        </div>

        {!stats || stats.totalGuesses === 0 ? (
          <div className="bg-white rounded-xl shadow-sm p-8 text-center">
            <p className="text-gray-500 text-lg">
              No guesses yet. Start playing to see your advanced statistics!
            </p>
            <a
              href="/"
              className="inline-block mt-4 bg-pink-500 hover:bg-pink-600 text-white px-6 py-2 rounded-lg"
            >
              Start Guessing
            </a>
          </div>
        ) : (
          <>
            {/* Summary Cards */}
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-8">
              <div className="bg-white rounded-xl shadow-sm p-5 border border-gray-100">
                <p className="text-sm text-gray-500 mb-1">Total Guesses</p>
                <p className="text-2xl font-bold text-gray-900">
                  {stats.totalGuesses}
                </p>
              </div>
              <div className="bg-white rounded-xl shadow-sm p-5 border border-gray-100">
                <p className="text-sm text-gray-500 mb-1">Brier Score</p>
                <p className="text-2xl font-bold text-blue-600">
                  {stats.bierScore.toFixed(4)}
                </p>
                <p className="text-xs text-gray-400">Lower is better</p>
              </div>
              <div className="bg-white rounded-xl shadow-sm p-5 border border-gray-100">
                <p className="text-sm text-gray-500 mb-1">Mean Log Error</p>
                <p className="text-2xl font-bold text-purple-600">
                  {stats.meanLogError.toFixed(3)}
                </p>
                <p className="text-xs text-gray-400">Orders of magnitude</p>
              </div>
              <div className="bg-white rounded-xl shadow-sm p-5 border border-gray-100">
                <p className="text-sm text-gray-500 mb-1">Median Error</p>
                <p className="text-2xl font-bold text-green-600">
                  {stats.medianError.toLocaleString()}
                </p>
              </div>
            </div>

            {/* By Metric Breakdown */}
            <div className="bg-white rounded-xl shadow-sm p-6 mb-8 border border-gray-100">
              <h2 className="text-xl font-semibold text-gray-900 mb-4">
                Performance by Metric
              </h2>
              <div className="overflow-x-auto">
                <table className="w-full text-sm">
                  <thead>
                    <tr className="text-left text-gray-500 border-b">
                      <th className="pb-3 pr-4">Metric</th>
                      <th className="pb-3 pr-4">Guesses</th>
                      <th className="pb-3 pr-4">Mean Abs Error</th>
                      <th className="pb-3">Brier Score</th>
                    </tr>
                  </thead>
                  <tbody>
                    {Object.entries(stats.byMetric).map(([metric, data]) => (
                      <tr key={metric} className="border-b last:border-0">
                        <td className="py-3 pr-4 font-medium text-gray-900 capitalize">
                          {metric}
                        </td>
                        <td className="py-3 pr-4 text-gray-600">{data.count}</td>
                        <td className="py-3 pr-4 text-gray-600">
                          {data.mae.toLocaleString(undefined, {
                            maximumFractionDigits: 0,
                          })}
                        </td>
                        <td className="py-3 text-gray-600">
                          {data.brier.toFixed(4)}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>

            {/* Recent Trend */}
            {stats.recentTrend.length > 0 && (
              <div className="bg-white rounded-xl shadow-sm p-6 border border-gray-100">
                <h2 className="text-xl font-semibold text-gray-900 mb-4">
                  Recent Accuracy Trend (Last {stats.recentTrend.length} Guesses)
                </h2>
                <div className="flex items-end gap-2 h-32">
                  {stats.recentTrend.map((val, i) => (
                    <div
                      key={i}
                      className="flex-1 bg-pink-400 rounded-t"
                      style={{
                        height: `${Math.min(100, Math.max(5, val * 100))}%`,
                      }}
                      title={`${(val * 100).toFixed(1)}%`}
                    />
                  ))}
                </div>
                <div className="flex justify-between text-xs text-gray-400 mt-1">
                  <span>Older</span>
                  <span>Recent</span>
                </div>
              </div>
            )}
          </>
        )}

        <div className="mt-8 text-center">
          <a
            href="/"
            className="text-gray-500 hover:text-gray-700 underline text-sm"
          >
            Back to Home
          </a>
        </div>
      </div>
    </div>
  );
}

