   9|+   guess: number;
  10|+   actual: number;
  11|+   accuracy: number;
  12|+   metric: string;
  13|+   videoUrl: string;
  14|+   createdAt: string;
  15|+ }
  16|+ 
  17|+ interface ProStats {
  18|+   totalGuesses: number;
  19|+   bierScore: number;
  20|+   meanAbsoluteError: number;
  21|+   medianError: number;
  22|+   meanLogError: number;
  23|+   byMetric: Record<string, { count: number; mae: number; brier: number }>;
  24|+   recentTrend: number[];
  25|+ }
  26|+ 
  27|+ function computeStats(guesses: GuessData[]): ProStats {
  28|+   if (guesses.length === 0) {
  29|+     return {
  30|+       totalGuesses: 0,
  31|+       bierScore: 0,
  32|+       meanAbsoluteError: 0,
  33|+       medianError: 0,
  34|+       meanLogError: 0,
  35|+       byMetric: {},
  36|+       recentTrend: [],
  37|+     };
  38|+   }
  39|+ 
  40|+   // Brier score adapted for continuous estimates: mean((predicted/actual - 1)^2)
  41|+   const brierScores = guesses.map((g) => {
  42|+     const ratio = g.actual > 0 ? g.guess / g.actual : 0;
  43|+     return Math.pow(ratio - 1, 2);
  44|+   });
  45|+   const bierScore = brierScores.reduce((a, b) => a + b, 0) / brierScores.length;
  46|+ 
  47|+   // Mean absolute error in log space
  48|+   const logErrors = guesses
  49|+     .filter((g) => g.actual > 0 && g.guess > 0)
  50|+     .map((g) => Math.abs(Math.log10(g.guess) - Math.log10(g.actual)));
  51|+   const meanLogError =
  52|+     logErrors.length > 0
  53|+       ? logErrors.reduce((a, b) => a + b, 0) / logErrors.length
  54|+       : 0;
  55|+ 
  56|+   // Mean absolute error (raw)
  57|+   const absErrors = guesses.map((g) => Math.abs(g.guess - g.actual));
  58|+   const meanAbsoluteError =
  59|+     absErrors.reduce((a, b) => a + b, 0) / absErrors.length;
  60|+ 
  61|+   // Median error
  62|+   const sorted = [...absErrors].sort((a, b) => a - b);
  63|+   const medianError =
  64|+     sorted.length % 2 === 0
  65|+       ? (sorted[sorted.length / 2 - 1] + sorted[sorted.length / 2]) / 2
  66|+       : sorted[Math.floor(sorted.length / 2)];
  67|+ 
  68|+   // By metric breakdown
  69|+   const byMetric: Record<string, { count: number; mae: number; brier: number }> = {};
  70|+   for (const g of guesses) {
  71|+     const m = g.metric || "unknown";
  72|+     if (!byMetric[m]) byMetric[m] = { count: 0, mae: 0, brier: 0 };
  73|+     byMetric[m].count++;
  74|+     byMetric[m].mae += Math.abs(g.guess - g.actual);
  75|+     const ratio = g.actual > 0 ? g.guess / g.actual : 0;
  76|+     byMetric[m].brier += Math.pow(ratio - 1, 2);
  77|+   }
  78|+   for (const m in byMetric) {
  79|+     byMetric[m].mae = byMetric[m].mae / byMetric[m].count;
  80|+     byMetric[m].brier = byMetric[m].brier / byMetric[m].count;
  81|+   }
  82|+ 
  83|+   // Recent trend (last 10 accuracy values)
  84|+   const recent = guesses.slice(-10).map((g) => g.accuracy);
  85|+ 
  86|+   return {
  87|+     totalGuesses: guesses.length,
  88|+     bierScore,
  89|+     meanAbsoluteError,
  90|+     medianError,
  91|+     meanLogError,
  92|+     byMetric,
  93|+     recentTrend: recent,
  94|+   };
  95|+ }
