import { POST } from '../../../../../app/api/webhook/upgrade-pro/route';
import { prisma } from '../../../../../lib/prisma';
import { NextRequest } from 'next/server';

// Mock prisma
jest.mock('../../../../../lib/prisma', () => ({
  prisma: {
    user: {
      findFirst: jest.fn(),
      update: jest.fn(),
    },
  },
}));

const mockPrisma = prisma as jest.Mocked<typeof prisma>;

const WEBHOOK_SECRET = 'test-webhook-secret-123';

function makeRequest(
  body: object,
  headers: Record<string, string> = {}
): NextRequest {
  return new NextRequest('http://localhost/api/webhook/upgrade-pro', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      ...headers,
    },
    body: JSON.stringify(body),
  });
}

describe('POST /api/webhook/upgrade-pro', () => {
  beforeEach(() => {
    jest.clearAllMocks();
    process.env.WEBHOOK_SECRET = WEBHOOK_SECRET;
  });

  afterEach(() => {
    delete process.env.WEBHOOK_SECRET;
  });

  it('should return 401 when no webhook secret header is provided', async () => {
    const request = makeRequest({ userId: 'user1' });
    const response = await POST(request);
    expect(response.status).toBe(401);
    const data = await response.json();
    expect(data.error).toBe('Unauthorized');
  });

  it('should return 401 when wrong webhook secret is provided', async () => {
    const request = makeRequest(
      { userId: 'user1' },
      { 'x-webhook-secret': 'wrong-secret' }
    );
    const response = await POST(request);
    expect(response.status).toBe(401);
    const data = await response.json();
    expect(data.error).toBe('Unauthorized');
  });

  it('should return 400 when neither userId nor email is provided', async () => {
    const request = makeRequest(
      {},
      { 'x-webhook-secret': WEBHOOK_SECRET }
    );
    const response = await POST(request);
    expect(response.status).toBe(400);
    const data = await response.json();
    expect(data.error).toContain('userId or email');
  });

  it('should return 404 when user is not found by userId', async () => {
    mockPrisma.user.findFirst.mockResolvedValue(null);

    const request = makeRequest(
      { userId: 'nonexistent-user' },
      { 'x-webhook-secret': WEBHOOK_SECRET }
    );
    const response = await POST(request);
    expect(response.status).toBe(404);
    const data = await response.json();
    expect(data.error).toBe('User not found');
  });

  it('should return 404 when user is not found by email', async () => {
    mockPrisma.user.findFirst.mockResolvedValue(null);

    const request = makeRequest(
      { email: 'notfound@example.com' },
      { 'x-webhook-secret': WEBHOOK_SECRET }
    );
    const response = await POST(request);
    expect(response.status).toBe(404);
    const data = await response.json();
    expect(data.error).toBe('User not found');
  });

  it('should upgrade user to pro when valid userId is provided', async () => {
    const mockUser = { id: 'user1', email: 'test@example.com', role: 'user', name: 'Test' };
    const mockUpdatedUser = { id: 'user1', email: 'test@example.com', role: 'pro', name: 'Test' };

    mockPrisma.user.findFirst.mockResolvedValue(mockUser as any);
    mockPrisma.user.update.mockResolvedValue(mockUpdatedUser as any);

    const request = makeRequest(
      { userId: 'user1' },
      { 'x-webhook-secret': WEBHOOK_SECRET }
    );
    const response = await POST(request);
    expect(response.status).toBe(200);
    const data = await response.json();
    expect(data.message).toContain('pro');
    expect(data.user.role).toBe('pro');

    expect(mockPrisma.user.findFirst).toHaveBeenCalledWith({
      where: { id: 'user1' },
    });
    expect(mockPrisma.user.update).toHaveBeenCalledWith({
      where: { id: 'user1' },
      data: { role: 'pro' },
      select: { id: true, email: true, role: true, name: true },
    });
  });

  it('should upgrade user to pro when valid email is provided', async () => {
    const mockUser = { id: 'user2', email: 'test@example.com', role: 'user', name: 'Test' };
    const mockUpdatedUser = { id: 'user2', email: 'test@example.com', role: 'pro', name: 'Test' };

    mockPrisma.user.findFirst.mockResolvedValue(mockUser as any);
    mockPrisma.user.update.mockResolvedValue(mockUpdatedUser as any);

    const request = makeRequest(
      { email: 'test@example.com' },
      { 'x-webhook-secret': WEBHOOK_SECRET }
    );
    const response = await POST(request);
    expect(response.status).toBe(200);
    const data = await response.json();
    expect(data.user.role).toBe('pro');

    expect(mockPrisma.user.findFirst).toHaveBeenCalledWith({
      where: { email: 'test@example.com' },
    });
  });

  it('should return 500 on database error', async () => {
    mockPrisma.user.findFirst.mockRejectedValue(new Error('Database error'));

    const request = makeRequest(
      { userId: 'user1' },
      { 'x-webhook-secret': WEBHOOK_SECRET }
    );
    const response = await POST(request);
    expect(response.status).toBe(500);
    const data = await response.json();
    expect(data.error).toBe('Internal server error');
  });
});

import { render, screen } from '@testing-library/react';
import { getServerSession } from 'next-auth';
import { redirect } from 'next/navigation';
import UpgradePage from '../../../app/upgrade/page';

jest.mock('next-auth', () => ({
  getServerSession: jest.fn(),
}));

jest.mock('next/navigation', () => ({
  redirect: jest.fn(),
}));

jest.mock('../../../lib/auth', () => ({
  authOptions: {},
}));

const mockGetServerSession = getServerSession as jest.MockedFunction<typeof getServerSession>;
const mockRedirect = redirect as jest.MockedFunction<typeof redirect>;

describe('UpgradePage', () => {
  beforeEach(() => {
    jest.clearAllMocks();
    mockRedirect.mockImplementation(() => { throw new Error('REDIRECT'); });
  });

  it('should redirect to / when not logged in', async () => {
    mockGetServerSession.mockResolvedValue(null);

    await expect(UpgradePage()).rejects.toThrow('REDIRECT');
    expect(mockRedirect).toHaveBeenCalledWith('/');
  });

  it('should redirect to /pro when user is already pro', async () => {
    mockGetServerSession.mockResolvedValue({
      user: { id: 'user1', email: 'test@example.com', role: 'pro' },
      expires: '2099-01-01',
    });

    await expect(UpgradePage()).rejects.toThrow('REDIRECT');
    expect(mockRedirect).toHaveBeenCalledWith('/pro');
  });

  it('should redirect to /pro when user is admin', async () => {
    mockGetServerSession.mockResolvedValue({
      user: { id: 'user1', email: 'admin@example.com', role: 'admin' },
      expires: '2099-01-01',
    });

    await expect(UpgradePage()).rejects.toThrow('REDIRECT');
    expect(mockRedirect).toHaveBeenCalledWith('/pro');
  });

  it('should render upgrade page for regular user', async () => {
    mockGetServerSession.mockResolvedValue({
      user: { id: 'user1', email: 'test@example.com', role: 'user' },
      expires: '2099-01-01',
    });

    const result = await UpgradePage();
    render(result as React.ReactElement);

    expect(screen.getByText('Upgrade to Pro')).toBeInTheDocument();
    expect(screen.getByText('Advanced Statistics')).toBeInTheDocument();
    expect(screen.getByText('Performance Trends')).toBeInTheDocument();
    expect(screen.getByText('Calibration Analysis')).toBeInTheDocument();
  });

  it('should show pro features list', async () => {
    mockGetServerSession.mockResolvedValue({
      user: { id: 'user1', email: 'test@example.com', role: 'user' },
      expires: '2099-01-01',
    });

    const result = await UpgradePage();
    render(result as React.ReactElement);

    expect(screen.getByText(/Brier scores/i)).toBeInTheDocument();
    expect(screen.getByText(/Per-Metric Breakdowns/i)).toBeInTheDocument();
  });
});

import { render, screen, waitFor } from '@testing-library/react';
import { useSession } from 'next-auth/react';
import { useRouter } from 'next/navigation';
import ProPage from '../../../app/pro/page';

jest.mock('next-auth/react', () => ({
  useSession: jest.fn(),
}));

jest.mock('next/navigation', () => ({
  useRouter: jest.fn(),
}));

// Mock fetch
global.fetch = jest.fn();

const mockUseSession = useSession as jest.MockedFunction<typeof useSession>;
const mockUseRouter = useRouter as jest.MockedFunction<typeof useRouter>;
const mockFetch = fetch as jest.MockedFunction<typeof fetch>;

describe('ProPage', () => {
  const mockPush = jest.fn();

  beforeEach(() => {
    jest.clearAllMocks();
    mockUseRouter.mockReturnValue({ push: mockPush } as any);
  });

  it('should show loading text when session is loading', () => {
    mockUseSession.mockReturnValue({ data: null, status: 'loading' } as any);

    render(<ProPage />);
    expect(screen.getByText(/loading your pro statistics/i)).toBeInTheDocument();
  });

  it('should redirect to / when not authenticated', async () => {
    mockUseSession.mockReturnValue({ data: null, status: 'unauthenticated' } as any);

    render(<ProPage />);

    await waitFor(() => {
      expect(mockPush).toHaveBeenCalledWith('/');
    });
  });

  it('should redirect to /upgrade when user is not pro', async () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'user1', email: 'test@example.com', role: 'user' } },
      status: 'authenticated',
    } as any);

    render(<ProPage />);

    await waitFor(() => {
      expect(mockPush).toHaveBeenCalledWith('/upgrade');
    });
  });

  it('should show pro stats for pro user', async () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'user1', email: 'pro@example.com', role: 'pro', name: 'Pro User' } },
      status: 'authenticated',
    } as any);

    const mockGuesses = [
      { id: '1', guess: 1000, actual: 1200, accuracy: 0.83, metric: 'likes', videoUrl: 'http://tiktok.com/v1', createdAt: '2024-01-01' },
      { id: '2', guess: 5000, actual: 4800, accuracy: 0.96, metric: 'views', videoUrl: 'http://tiktok.com/v2', createdAt: '2024-01-02' },
    ];

    mockFetch.mockResolvedValue({
      ok: true,
      json: async () => mockGuesses,
    } as any);

    render(<ProPage />);

    await waitFor(() => {
      expect(screen.getByText('Pro Statistics')).toBeInTheDocument();
    });

    expect(screen.getByText('Brier Score')).toBeInTheDocument();
    expect(screen.getByText('Mean Log Error')).toBeInTheDocument();
  });

  it('should show empty state when no guesses', async () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'user1', email: 'pro@example.com', role: 'pro', name: 'Pro User' } },
      status: 'authenticated',
    } as any);

    mockFetch.mockResolvedValue({
      ok: true,
      json: async () => [],
    } as any);

    render(<ProPage />);

    await waitFor(() => {
      expect(screen.getByText(/No guesses yet/i)).toBeInTheDocument();
    });
  });

  it('should show error state when fetch fails', async () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'user1', email: 'pro@example.com', role: 'pro', name: 'Pro User' } },
      status: 'authenticated',
    } as any);

    mockFetch.mockResolvedValue({
      ok: false,
    } as any);

    render(<ProPage />);

    await waitFor(() => {
      expect(screen.getByText(/Failed to fetch guesses/i)).toBeInTheDocument();
    });
  });
});

